        return "a", "a"
    len_t = max(1, n // 2)
    len_s = n

    alphabet = ["a", "b", "c"]

    def char_from_idx(idx):
        return alphabet[(idx + case_index) % len(alphabet)]

    s = [char_from_idx(i) for i in range(len_s)]
    t = [alphabet[(i * 2 + case_index) % len(alphabet)] for i in range(len_t)]
    return "".join(s), "".join(t)


