            return deep(c, d, visited)

def build_deterministic_tree(n):
    d = {}
    if n == 1:
        d[1] = []
        return d
    for i in range(2, n + 1):
        u = i
        v = i // 2
        d.setdefault(u, []).append(v)
        d.setdefault(v, []).append(u)
    return d

def core_algorithm(n, d):
    node = 1
    for key in d:
        if len(d[key]) > len(d[node]):
            node = key
    ans = []
    visited = [0] * n
    visited[node - 1] = 1
    for c in d[node]:
        while True:
            visited[c - 1] = 1
            if len(d[c]) == 1:
                ans.append([node, c])
                break
            progressed = False
            for child in d[c]:
                if visited[child - 1] != 1:
                    c = child
                    progressed = True
                    break
            if not progressed:
                break
    if sum(visited) == n:
        output_lines = []
        output_lines.append("Yes")
        output_lines.append(str(len(ans)))
        for c in ans:
            output_lines.append(f"{c[0]} {c[1]}")
        return "\n".join(output_lines)

    else:
        return "No"

