import sys

def generate_input(n):
    # 第一行：占位（原代码中被丢弃）
    # 第二行：n 个互不相同的整数，构成一个排列结构
    # 使用确定性的构造方式，无随机
    if n <= 0:
        n = 1
    arr = [(i * 2 + 3) % n for i in range(n)]
    # 为保证是排列且元素从 0..n-1 打乱后再平移到 1..n
    seen = set()
    perm = []
    for v in arr:
        if v not in seen:
            seen.add(v)
            perm.append(v)
    # 补齐缺失的元素
    for v in range(n):
        if v not in seen:
            perm.append(v)
    # 现在 perm 是 0..n-1 的排列，将其平移到 1..n
    perm = [v + 1 for v in perm[:n]]
    # 构造模拟输入（第一行随意，第二行为排列）
    lines = []
    lines.append(str(n))
    lines.append(" ".join(str(x) for x in perm))
    return lines

def main(n):
    lines = generate_input(n)
    it = iter(lines)

    # 丢弃第一行
    next(it)

