                next_position += x

            next_position = position - x
            while next_position >= 0:
                if pos2x[next_position] > x and answers[next_position] == "B":
                    return True
                next_position -= x

            return False

        if can_go_to_looser():
            answers[position] = "A"

        else:
            answers[position] = "B"

    result = ''.join(answers)
    # print(result)
