    nos.sort()
    return nos[0] + 1 == nos[1] and nos[1] + 1 == nos[2] and len(set([ele[1] for ele in arr])) == 1

def core_logic(arr):
    if isshuntsu(arr) or iskoutsu(arr):
        return 0

    total1 = 0
    if len(set(arr)) == 3:
        total1 = 2
    elif len(set(arr)) == 2:
        total1 = 1

