            required = [str(no + 1) + suite, str(no + 2) + suite]
            curr = int(required[0] not in arr) + int(required[1] not in arr)
            total2 = min(total2, curr)

        if no + 1 <= 9 and no - 1 >= 0:
            required = [str(no - 1) + suite, str(no + 1) + suite]
            curr = int(required[0] not in arr) + int(required[1] not in arr)
            total2 = min(total2, curr)

